// Saveur N°5 — Recettes Espagne (58 recettes)
RECIPES.push(
{id:"AC009",co:"Espagne",cat:"Accompagnement",sous:"Légumes",nom:"Pimientos del Piquillo Rellenos",chef:"Tradition navarraise",bp:4,prep:20,cui:20,diff:2,qual:4,ig:[["Pimientos del piquillo en conserve",12,"pièces"],["Morue dessalée effilochée",200,"g"],["Pommes de terre cuites écrasées",150,"g"],["Ail",2,"gousses"],["Huile d'olive",3,"cs"],["Persil",2,"cs"],["Paprika fumé",1,"cc"],["Crème fraîche",5,"cs"]],et:"1. Préparer la farce : mélanger morue effilochée + purée de pommes de terre + ail haché + persil + paprika + 2cs crème. Assaisonner.\n2. Farcir délicatement chaque piquillo avec la farce.\n3. Poser dans un plat. Napper du jus de conserve des piquillos.\n4. Sauce : mixer quelques piquillos restants + crème fraîche + sel. Chauffer doucement.\n5. Four 180°C 15 min. Servir nappés de sauce piquillo crème.",vin:"Rioja Blanco ou Albariño",notes:"Les pimientos del piquillo de Navarre (AOP) sont doux, charnus et légèrement fumés. Ils sont irremplaçables."},
{id:"AC010",co:"Espagne",cat:"Accompagnement",sous:"Pain",nom:"Pan con Tomate (Pa amb Tomàquet)",chef:"Tradition catalane",bp:4,prep:5,cui:5,diff:1,qual:5,ig:[["Pain de campagne rustique",8,"tranches"],["Tomates très mûres",3,"pièces"],["Ail",2,"gousses"],["Huile d'olive extra-vierge",6,"cs"],["Fleur de sel",1,"qs"]],et:"1. Griller les tranches de pain épaisses sous le gril ou à la plancha jusqu'à légèrement croustillantes.\n2. Frotter immédiatement chaque tranche avec la gousse d'ail coupée en deux.\n3. Frotter ensuite avec la tomate coupée en deux — la pulpe doit s'imprégner dans le pain.\n4. Arroser généreusement d'huile d'olive.\n5. Fleur de sel. Servir immédiatement.",vin:"Accompagnement de tout le repas espagnol",notes:"La tomate doit être très mûre. La frotter vigoureusement pour bien imprégner le pain. L'huile doit être de grande qualité."},
{id:"AS_ES01",co:"Espagne",cat:"Assaisonnement",sous:"Épice",nom:"Pimentón de la Vera — Recettes d'Usage",chef:"Tradition d'Estrémadure",bp:4,prep:5,cui:5,diff:1,qual:5,ig:[["Pimentón de la Vera DOP fumé doux",3,"cs"],["Huile d'olive",3,"cs"],["Ail",2,"gousses"],["Sel",1,"cs"]],et:"1. Ail écrasé, frit doucement dans l'huile 1 min. Retirer du feu.\n2. Ajouter le pimentón HORS FEU (il brûle instantanément au contact de l'huile chaude).\n3. Remettre sur feu 30 sec en remuant. Obtenir une huile rouge orangée.\n4. Cette base aromatique se prépare à la minute et s'utilise immédiatement.\n5. Applications : chorizo maison, poulet rôti, patatas bravas, légumes rôtis, sauces.",vin:"Usage universel dans la cuisine espagnole",notes:"Le pimentón de la Vera est fumé sur chêne — il est irremplaçable par du paprika ordinaire. L'ajouter hors feu est impératif pour préserver son arôme."},
{id:"ES001",co:"Espagne",cat:"Plat",sous:"Poisson / Mer",nom:"Gambas al Ajillo (Crevettes à l'Ail)",chef:"Tradition andalouse",bp:4,prep:15,cui:10,diff:1,qual:4,ig:[["Gambas ou langoustines fraîches décortiquées",800,"g"],["Ail émincé finement",8,"gousses"],["Piments guindilla secs",2,"pièces"],["Huile d'olive vierge extra Arbequina",20,"cl"],["Paprika fumé doux pimentón de La Vera",1,"cs"],["Persil plat haché",1,"bouquet"]],et:"1. Utiliser une poêle ou cazuela en terre cuite.\n2. Chauffer l'huile d'olive à feu moyen-vif. Ajouter l'ail + piments. Dorer l'ail légèrement blond (NE JAMAIS brûler).\n3. Monter à feu VIF. Ajouter les gambas en une seule couche. Saupoudrer de paprika fumé.\n4. Cuire 1 min 30 de chaque côté (gambas rosées et légèrement caramélisées).\n5. Assaisonner. Parsemer de persil haché.\n6. Servir IMMÉDIATEMENT dans la cazuela brûlante avec pain grillé frotté à l'ail.",vin:"Manzanilla en Rama de Sanlúcar de Barrameda ou Albariño Rías Baixas",notes:"La qualité de l'huile d'olive Arbequina est primordiale. La rapidité de cuisson est le secret pour des gambas tendres et juteuses."},
{id:"ES002",co:"Espagne",cat:"Plat",sous:"Riz",nom:"Paella Valenciana Authentique",chef:"Tradition valencienne",bp:6,prep:30,cui:45,diff:4,qual:4,ig:[["Riz à paella Bomba ou Calasparra",500,"g"],["Bouillon de volaille chaud",150,"cl"],["Safran en pistils",0.5,"g"],["Poulet fermier en morceaux",1200,"g"],["Haricots verts plats",300,"g"],["Haricots blancs cuits",200,"g"],["Tomates mûres râpées",3,"pièces"],["Paprika fumé doux",1,"cs"],["Huile d'olive",4,"cs"]],et:"1. Chauffer l'huile d'olive dans la poêle à paella. Dorer les morceaux de poulet sur toutes les faces. Réserver.\n2. Faire revenir les haricots verts 5 min. Ajouter les tomates râpées, cuire jusqu'à concentration (sofrito).\n3. Ajouter le paprika fumé, remuer vite 30 sec.\n4. Ajouter le riz, nacrer 2 min en remuant.\n5. Mouiller avec le bouillon chaud + infusion de safran. Remuer UNE SEULE FOIS pour égaliser, puis NE PLUS REMUER.\n6. Remettre le poulet et les haricots blancs. Disposer sur feu vif les 5 premières minutes, puis feu moyen-doux 15 min.\n7. Socarrat : les 2 dernières minutes, monter légèrement le feu pour caraméliser le fond (on entend crépiter).\n8. Repos 5 min couvert de papier journal. Servir directement dans la poêle.",vin:"Cava Brut Nature ou vin blanc sec valencien ; Bobal tinto",notes:"La vraie paella valenciana ne contient NI chorizo NI poivrons. Le socarrat (fond caramélisé) est la récompense du cuisinier."},
{id:"ES003",co:"Espagne",cat:"Dessert",sous:"Crème / Entremets",nom:"Crema Catalana",chef:"Tradition catalane",bp:6,prep:20,cui:30,diff:2,qual:4,ig:[["Jaunes d'œufs",6,"pièces"],["Sucre semoule",150,"g"],["Lait entier",100,"cl"],["Zeste de citron non traité",1,"pièce"],["Bâton de cannelle",1,"pièce"],["Fécule de maïs Maïzena",30,"g"],["Sucre roux pour caramélisation",60,"g"]],et:"1. Infuser à feu doux le lait + zeste citron + cannelle 15 min (ne pas bouillir). Filtrer.\n2. Fouetter jaunes + sucre jusqu'à blanchiment. Incorporer la fécule tamisée.\n3. Verser le lait infusé chaud sur les jaunes en remuant. Remettre dans la casserole.\n4. Cuire à feu moyen en remuant constamment jusqu'à épaississement (max 82°C).\n5. Verser dans les ramequins plats. Refroidir, réfrigérer au moins 4 h.\n6. Saupoudrer de sucre roux. Caraméliser au fer à brûler chauffé à blanc ou au chalumeau.",vin:"Moscatel de Valencia ou Cava Brut Nature",notes:"Précurseur de la crème brûlée française (antériorité débattue depuis le XVIIe siècle). La fécule garantit une texture plus lisse."},
{id:"ES004",co:"Espagne",cat:"Entrée",sous:"Soupe froide",nom:"Gazpacho Andalouz Premium aux Tomates de Pera (Création Quique Dacosta)",chef:"Quique Dacosta (★★★, Quique Dacosta Restaurante, Dénia)",bp:6,prep:30,cui:0,diff:2,qual:5,ig:[["Tomates Cœur de Bœuf très mûres (variété Raf de Almería)",1200,"g"],["Concombre de Almería (peau fine)",1,"pièce"],["Poivron rouge italien (vert pour version traditionnelle Cordoba)",1,"pièce"],["Poivron jaune (équilibre douceur)",0.5,"pièce"],["Ail rose nouveau",2,"gousses"],["Pain de mie blanc rassis (sans croûte)",80,"g"],["Vinaigre de Xérès Reserva PX",4,"cs"],["Huile d'olive AOP Sierra Mágina (Picual)",15,"cl"],["Sel de mer Atlantique",1,"qs"],["Eau de source minérale très froide",10,"cl"],["Cumin moulu",1,"pincée"],["Glaçons (pour service)",1,"qs"]],et:"SÉLECTION DES TOMATES (la base absolue selon Quique Dacosta) :\n1. Choisir des tomates Raf d'Almería (la \"reine de l'Andalousie\") en fin d'été — elles doivent être très molles, parfumées, presque trop mûres. Une tomate ferme = un gazpacho fade. À défaut, des cœurs de bœuf bien mûrs en septembre.\nMONDAGE (technique restaurant ★★★) :\n2. Inciser le cul des tomates en croix. Plonger 30 sec dans l'eau bouillante. Refroidir aussitôt à l'eau glacée. Peler — la peau s'enlève d'un seul geste.\n3. Couper en quartiers, ÉPÉPINER (étape essentielle pour Dacosta — donne un gazpacho velours, sans amertume). Récupérer le jus précieux des graines en pressant à travers un chinois.\nMARINADE FROIDE (technique Quique Dacosta) :\n4. Faire tremper le pain rassis dans l'eau minérale froide 10 min. Essorer délicatement entre les paumes.\n5. Dans un saladier, mettre les tomates pelées et épépinées + concombre épluché en gros morceaux + poivrons épépinés et déveinés en cubes + ail dégermé.\n6. Ajouter le pain trempé + vinaigre de Xérès + sel + cumin.\n7. Mariner couvert au réfrigérateur PENDANT 2 H — étape essentielle qui développe les arômes en profondeur.\nMIXAGE (technique Quique Dacosta — texture velours) :\n8. Mixer au blender de très haute puissance (Vitamix ou Pacojet) pendant 5 min — la durée fait toute la différence pour atteindre une texture parfaitement onctueuse.\n9. Sans arrêter le mixeur, verser l'huile d'olive AOP Sierra Mágina en filet TRÈS lent — comme une mayonnaise. L'émulsion doit être stable et soyeuse.\nFILTRATION DOUBLE (signature ★★★) :\n10. Passer une PREMIÈRE FOIS au chinois fin en pressant à la louche.\n11. Passer une DEUXIÈME FOIS au chinois étamine (mousseline) — le résultat est un velouté glacé d'une finesse extraordinaire, sans aucune fibre.\nRECTIFICATION CHEF :\n12. Goûter à froid : le froid masque les saveurs. Toujours saler et acidifier PLUS qu'à chaud. Si trop dense, détendre avec un peu d'eau minérale glacée.\nREFROIDISSEMENT FINAL :\n13. Réfrigérer dans un récipient hermétique 4 H minimum (idéalement 12 h) — le gazpacho doit être glacial.\nSERVICE QUIQUE DACOSTA :\n14. Refroidir des bols à soupe au congélateur 30 min avant.\n15. Verser le gazpacho. Glaçon écrasé au centre.\n16. Garniture finale : tomates concassées en brunoise + concombre + poivron + ¼ d'œuf dur + croûton de pain à l'ail + filet d'huile d'olive AOP cru + 2 feuilles de basilic.",vin:"Manzanilla en rama (Sherry Sanlúcar) ou Cava Rosé Brut Nature",notes:"Quique Dacosta (★★★, Dénia, élu plusieurs fois Top 50 World) : \"Le gazpacho est la quintessence du goût andaloux : 100% cru, jamais cuit, mais avec la complexité d'un grand plat. Le secret est la double filtration au chinois étamine — c'est ce qui fait la différence entre une soupe campagnarde et une émulsion étoilée.\" Le gazpacho se réinvente chaque été depuis le XIXe siècle ; cette recette est la version la plus aboutie."},
{id:"ES005",co:"Espagne",cat:"Entrée",sous:"Tapas",nom:"Patatas Bravas avec Salsa Brava et Aïoli (Recette Original Madrid 1962)",chef:"José Carlos Capel (référence madrilène) / Sergi Arola (★, Madrid)",bp:4,prep:25,cui:30,diff:2,qual:5,ig:[["Pommes de terre Agria ou Ratte (chair ferme, peu d'eau)",1000,"g"],["Huile d'arachide pour friture (1 L minimum)",1,"L"],["Tomates pelées San Marzano",400,"g"],["Ail rose",4,"gousses"],["Pimentón de la Vera Picante (fumé piquant DOP)",2,"cs"],["Pimentón de la Vera Dulce (fumé doux DOP)",1,"cs"],["Vinaigre de Xérès Reserva",2,"cs"],["Cayenne piment frais ou tabasco",2,"pincées"],["Sucre",1,"pincée"],["Huile d'olive AOP Picual",6,"cs"],["Œuf entier (pour aïoli)",1,"pièce"],["Ail (pour aïoli)",2,"gousses"],["Huile de tournesol pour aïoli",15,"cl"],["Citron",0.5,"pièce"],["Sel de Cervia, poivre noir",1,"qs"]],et:"PRÉPARATION DES POMMES DE TERRE (technique Madrid double cuisson) :\n1. Éplucher les pommes de terre. Couper en cubes irréguliers de 3 cm (les angles donnent du croustillant).\n2. Plonger les cubes dans un bol d'eau froide, rincer 3 fois jusqu'à eau claire — élimine l'amidon de surface (essentiel pour la double friture).\n3. Sécher minutieusement entre 2 torchons.\nPRÉCUISSON À L'HUILE BASSE TEMPÉRATURE (\"blanching\" — étape professionnelle) :\n4. Chauffer l'huile à 130°C exactement.\n5. Plonger les pommes de terre. Cuire 8-10 min à 130°C SANS COLORATION jusqu'à fondantes au centre (test : transpercer à l'aiguille).\n6. Égoutter sur grille. Laisser refroidir 30 min — la baisse de température raffermit l'amidon, c'est le secret du croustillant final.\nSALSA BRAVA AUTHENTIQUE (recette Madrid 1962) :\n7. Dans une cocotte, chauffer 4 cs d'huile d'olive Picual. Faire revenir 4 gousses d'ail tranchées finement à feu doux jusqu'à blondes (jamais brun).\n8. Ajouter les pimentón doux et picant — cuire 30 secondes à peine (sinon brûlent et deviennent amers). Geste de chef.\n9. Verser les San Marzano écrasés à la main + sucre + sel.\n10. Frémir 25 min à feu moyen jusqu'à sauce épaisse et profonde.\n11. Mixer finement. Passer au chinois (texture velours). Ajouter le vinaigre de Xérès + cayenne. Rectifier le piquant — la salsa brava doit être ÉPICÉE et persistante mais pas brûlante.\nALIOLI MAISON (sans œuf — version pure mayonnaise catalane traditionnelle ou avec œuf — version moderne) :\n12. Version Sergi Arola : 2 gousses d'ail + 1 jaune + 1 cs jus de citron + sel au mortier en marbre. Travailler à la pomme jusqu'à pâte lisse.\n13. Verser l'huile de tournesol EN FILET TRÈS LENT (comme une mayonnaise) tout en pilant constamment dans le mortier — l'émulsion doit être ferme et brillante.\n14. Ajustement final : sel + filet de jus de citron pour acidulé.\nDEUXIÈME FRITURE (la magie du croustillant) :\n15. Chauffer l'huile à 190°C très haute température.\n16. Plonger les pommes de terre prébranchies. Frire 4-5 min jusqu'à très dorées et croustillantes (la coque doit craquer à la cuillère).\n17. Égoutter, sécher sur papier absorbant, saler immédiatement de sel marin.\nDRESSAGE MADRID (présentation tapas) :\n18. Disposer les pommes de terre dans un plat creux en céramique. Napper 1/3 de salsa brava (laisse les pommes croustillantes).\n19. Couvrir d'1 cs d'aïoli ferme — Madrid fait un \"Y\" décoratif. Casser le \"Y\" en mélangeant à la fourchette pour mêler les saveurs.\n20. Servir IMMÉDIATEMENT avec un cure-dent de bois (tradition tapas), une bière fraîche et un quartier de citron.",vin:"Cerveza Mahou Cinco Estrellas (bière Madrid) ou Albariño DO Rías Baixas",notes:"Selon José Carlos Capel (critique gastronomique référence) : la patata brava authentique a été créée vers 1962 à Madrid (Casa Pellico ou Las Bravas, controverse historique). La double friture (blanching à 130°C + finition à 190°C) est le secret professionnel pour des cubes croustillants à l'extérieur, fondants au cœur. La règle d'or : aïoli + brava DOIVENT figurer ensemble, jamais séparément. La brava sans aïoli est une hérésie madrilène."},
{id:"ES006",co:"Espagne",cat:"Plat",sous:"Poisson",nom:"Bacalà a la Llauna avec Aïoli au Safran (Recette Carme Ruscalleda)",chef:"Carme Ruscalleda (★★★, Sant Pau, Sant Pol de Mar)",bp:4,prep:30,cui:30,diff:3,qual:5,ig:[["Filets de morue dessalée 36 h (épaisseur 2,5 cm minimum)",800,"g"],["Tomates Raf très mûres",400,"g"],["Ail rose nouveau",6,"gousses"],["Persil plat catalan",1,"bouquet"],["Pimentón de la Vera Dulce",1,"cs"],["Pimentón de la Vera Picante",0.5,"cs"],["Vin blanc sec catalan (Penedès Xarel-lo)",10,"cl"],["Bouillon de poisson maison léger",15,"cl"],["Huile d'olive AOP Empordà (Argudell)",10,"cs"],["Farine T45 pour fariner",3,"cs"],["Aïoli au safran (recette infra)",4,"cs"],["Pignons de pin grillés",30,"g"],["Sel marin de Cap de Creus, poivre blanc",1,"qs"]],et:"DESSALAGE DE LA MORUE (J-2, méthode professionnelle) :\n1. Acheter de la morue salée en filets épais (catégorie première, du Cap-Vert ou de Norvège). Plonger dans une bassine d'eau fraîche au réfrigérateur. Changer l'eau toutes les 8 h pendant 36-48 h. Goûter à la fin pour vérifier (doit être salée mais agréable, pas violente).\n2. Sécher soigneusement les filets sur papier absorbant. Inspecter pour retirer toutes les arêtes éventuelles avec une pince à filet.\nAIOLI AU SAFRAN (\"allioli amb safrà\" — variante précieuse Ruscalleda) :\n3. Concasser 1 g de pistils de safran. Infuser 10 min dans 1 cs d'eau chaude.\n4. Au mortier en marbre : 2 gousses d'ail + sel. Piler en pâte lisse.\n5. Ajouter 1 jaune d'œuf + l'infusion de safran + 1 cs jus de citron. Émulsionner en cercles.\n6. Verser 12 cl d'huile d'olive en filet TRÈS LENT en battant constamment au pilon — l'émulsion doit prendre comme une mayonnaise. Si elle tranche, recommencer dans un nouveau bol avec un nouveau jaune.\n7. Réserver au frais.\nFARINAGE ET SAISIE (étape capitale) :\n8. Préchauffer le four à 200°C en chaleur statique.\n9. Saler très peu les filets (la morue est encore légèrement salée). Poivrer côté chair.\n10. Fariner uniquement la peau et les côtés — laisser la chair NUE pour une cuisson juste.\n11. Dans une grande poêle en fonte ou cazuela en terre cuite (\"llauna\" en catalan = \"plat de cuisson\"), chauffer 5 cs d'huile d'olive à feu très vif.\n12. Saisir la morue côté peau d'abord 2-3 min jusqu'à dorée et croustillante. Retourner. 1 min côté chair pour saisir uniquement (ne PAS cuire à cœur — finira au four).\n13. Réserver les filets sur assiette.\nSAUCE \"A LA LLAUNA\" (technique Ruscalleda) :\n14. Dans la même poêle, baisser à feu moyen. Ajouter 4 gousses d'ail tranchées finement. Dorer doucement 2 min sans brûler.\n15. Ajouter pimentón doux + picant (hors feu, sinon brûlent). Remuer 10 secondes.\n16. Verser le vin blanc Penedès. Réduire à sec en grattant les sucs.\n17. Ajouter les Raf concassées + bouillon de poisson. Frémir 8 min jusqu'à sauce concentrée.\n18. Goûter, rectifier (poivre, sel modéré).\nCUISSON FINALE A LA LLAUNA (au four) :\n19. Verser la sauce dans un plat à four (ou la cazuela utilisée). Poser les filets de morue côté peau VERS LE HAUT sur la sauce.\n20. Arroser de la sauce à la cuillère pour bien glacer la peau.\n21. Enfourner à 200°C pendant 7-10 min selon l'épaisseur — la chair doit être nacrée et juste cuite (test : se défait en lamelles fermes).\nDRESSAGE RUSCALLEDA :\n22. Disposer les filets dans des assiettes plates très chaudes. Napper de sauce.\n23. Au-dessus de chaque filet, déposer 1 généreuse cuillère d'aïoli au safran.\n24. Pignons grillés concassés + persil plat ciselé. Filet d'huile d'olive AOP Empordà cru.\n25. Servir IMMÉDIATEMENT avec une crouste de pain catalan grillé pour saucer.",vin:"Penedès Blanc Xarel-lo barrique (Albet i Noya) ou Priorat Garnatxa Blanca",notes:"Carme Ruscalleda (★★★, Sant Pau de Sant Pol de Mar — première Espagnole 3 étoiles) : \"La 'llauna' désigne le plat en métal traditionnel des pêcheurs catalans. La technique 'a la llauna' veut que le poisson finisse sa cuisson dans la sauce au four — préserve la jutosité tout en imprégnant les chairs des arômes. L'aïoli au safran (très onéreux) est ma signature pour ce plat — c'est la fusion entre la cuisine de la mer catalane et la richesse du safran de la Manche.\""},
{id:"ES007",co:"Espagne",cat:"Dessert",sous:"Friture",nom:"Churros con Chocolate à la Españole (Recette Chocolatería San Ginés 1894)",chef:"Chocolatería San Ginés (1894, Madrid — référence mondiale)",bp:4,prep:25,cui:20,diff:3,qual:5,ig:[["Eau",250,"ml"],["Beurre fin",60,"g"],["Farine T45 spéciale espagnole (forte)",250,"g"],["Sel fin",2,"g"],["Huile d'arachide pour friture (point de fumée 230°C)",1.5,"L"],["Sucre semoule fine pour saupoudrage",80,"g"],["Cannelle de Ceylan moulue",2,"cc"],["Chocolat noir 70% Valrhona Caraïbe",250,"g"],["Lait entier",50,"cl"],["Crème fleurette 35% MG",10,"cl"],["Sucre semoule pour chocolat chaud",30,"g"],["Maïzena (pour épaissir le chocolat)",2,"cs"],["Bâton de cannelle (infusion chocolat)",1,"pièce"],["Zeste d'orange (parfum optionnel)",1,"pièce"]],et:"CHOCOLATE ESPAGNOL (à préparer en premier — peut chauffer pendant qu'on fait les churros) :\n1. Hacher finement le chocolat Valrhona Caraïbe au couteau (jamais aux blocs trop gros — fond mal).\n2. Dans une casserole à fond épais, mélanger lait + crème + bâton de cannelle + zeste d'orange. Chauffer doucement à 80°C, hors feu, infuser 15 min couvert. Filtrer.\n3. Délayer la maïzena dans 3 cs de lait infusé tiède (\"slurry\").\n4. Reverser la maïzena délayée dans le lait infusé. Chauffer doucement en fouettant constamment jusqu'à frémissement (3-4 min). Le mélange doit napper le dos d'une cuillère.\n5. Hors feu, verser le chocolat haché. Laisser fondre 1 minute, puis émulsionner au fouet en mouvements circulaires. Le chocolat espagnol authentique est ÉPAIS, presque comme une crème — on doit pouvoir y dresser un churro debout.\n6. Maintenir au chaud (T° de service 65°C).\nPÂTE À CHURROS (recette \"choux\" sèche — différente de la française) :\n7. Dans une casserole épaisse, chauffer eau + beurre + sel jusqu'à frémissement (le beurre doit être fondu).\n8. Hors feu, verser TOUTE la farine d'un seul coup. Mélanger énergiquement à la cuillère en bois jusqu'à pâte homogène.\n9. Remettre 90 secondes à feu moyen en travaillant la pâte (\"deshidratar\") — elle doit former une boule lisse qui se détache des parois (la pâte siffle légèrement). Cette étape sèche la pâte et prépare la magie de la friture.\n10. Transférer dans une poche à douille étoile à 6 branches de 16 mm (le diamètre traditionnel madrilène). Reposer 10 min — la pâte se détend.\nFRITURE (technique Chocolatería San Ginés) :\n11. Chauffer l'huile à 195°C exactement (thermomètre obligatoire). Cette T° élevée est cruciale : pâte qui rentre = expansion immédiate sans absorption d'huile.\n12. Pocher des bâtonnets de 12-15 cm directement dans l'huile. Couper avec des ciseaux humides.\n13. NE PAS surcharger — 4 churros maximum. Frire 2,5 min jusqu'à dorées et craquelées (la signature \"craquelée\" vient de l'humidité de la pâte qui s'évapore).\n14. Égoutter sur papier absorbant. Saupoudrer immédiatement de sucre + cannelle pendant qu'ils sont chauds (le sucre adhère à l'humidité du churro).\nSERVICE TRADITIONNEL DE MADRID (rituel \"chocolate con churros\" depuis 1894) :\n15. Verser le chocolat épais dans des tasses chaudes (signature Chocolatería San Ginés : tasse en porcelaine épaisse).\n16. Dresser 4 churros par personne sur assiette plate. Le chocolat doit être suffisamment épais pour qu'on puisse y plonger le churro et qu'il le maintienne dressé.\n17. Tradition : tremper, secouer pour faire couler l'excès, mordre. Boire le reste du chocolat à la cuillère ou comme une boisson chaude.",vin:"Sherry PX Don PX (Toro Albalá, 30 ans) ou Bombazo (Brandy de Jerez)",notes:"Chocolatería San Ginés (Madrid, ouverte 1894 dans le Pasaje de San Ginés près de la Puerta del Sol) : \"Le chocolate con churros est le rituel d'après-fête à Madrid — on y va à 6 h du matin après une nuit blanche, ou pour le petit déjeuner du dimanche. Le chocolat espagnol authentique est si épais que les Français le trouvent indigeste — c'est notre fierté.\" La pâte sans œuf et la friture à 195°C donnent une texture craquelée caractéristique."},
{id:"ES008",co:"Espagne",cat:"Plat",sous:"Tortilla",nom:"Tortilla de Patatas Authentique aux Pommes de Terre Confites (Recette Quique Dacosta)",chef:"Quique Dacosta (★★★, Dénia)",bp:6,prep:25,cui:35,diff:3,qual:5,ig:[["Pommes de terre Agria ou Monalisa",1000,"g"],["Œufs frais bio extra-frais",10,"pièces"],["Oignon doux",1,"pièce"],["Huile d'olive AOP Picual extra-vierge",30,"cl"],["Sel marin",1,"qs"]],et:"CONFIT DES POMMES DE TERRE (technique Dacosta — étape capitale) :\n1. Éplucher pommes de terre, couper en rondelles fines de 3 mm.\n2. Émincer l'oignon en demi-rondelles fines.\n3. Dans grande sauteuse, chauffer huile d'olive à 90°C MAXIMUM (jamais frire — confire).\n4. Plonger pommes de terre + oignon. Confire 25 min à feu très doux — elles cuisent dans l'huile sans coloration.\n5. Égoutter sur grille (réserver l'huile parfumée pour autre usage). Saler.\nMÉLANGE ŒUFS-PDT (la magie Dacosta) :\n6. Battre œufs au fouet pour incorporer air (pas en mousse).\n7. Plonger pommes de terre confites tièdes dans œufs battus. Repos 10 min — les œufs absorbent l'amidon.\nCUISSON \"CREMOSA\" (la signature espagnole) :\n8. Dans poêle 24 cm anti-adhésive, chauffer 2 cs de l'huile parfumée à feu moyen.\n9. Verser le mélange. Cuire 4 min jusqu'à fond pris mais centre encore liquide.\n10. RETOURNER avec assiette : poser assiette retournée sur la poêle, retourner d'un coup. Glisser sur poêle.\n11. Cuire 2 min de l'autre côté — le centre doit rester BAVEUX (\"cremosa\" — texture coulante au cœur, signature absolue).\n12. Glisser sur assiette. Repos 5 min — la chaleur résiduelle finit la cuisson.\nSERVICE :\n13. Trancher en parts généreuses. Le centre doit \"baver\" légèrement — c'est la perfection espagnole.\n14. Servir avec pain rustique + tomates anchoïs + bière fraîche.",vin:"Cava Brut Nature ou Sherry Manzanilla",notes:"Quique Dacosta (★★★) : la vraie tortilla espagnole est CREMOSA (baveuse au centre) — la version cuite à fond est une trahison. Pommes de terre confites (jamais frites), oignon obligatoire (tradition basque-Madrid)."},
{id:"ES009",co:"Espagne",cat:"Entrée",sous:"Tapas",nom:"Croquetas de Jamón Ibérico Bellota (Recette Sergi Arola)",chef:"Sergi Arola (★★, Madrid)",bp:8,prep:90,cui:25,diff:3,qual:5,ig:[["Jamón Ibérico Bellota DOP haché fin",200,"g"],["Beurre fin",80,"g"],["Farine T45",100,"g"],["Lait entier frais",60,"cl"],["Crème fleurette 35%",10,"cl"],["Oignon doux râpé",0.5,"pièce"],["Œufs (panure)",2,"pièces"],["Chapelure panko",200,"g"],["Farine (panure)",80,"g"],["Huile arachide pour friture",1,"L"],["Sel, poivre blanc, muscade",1,"qs"]],et:"BÉCHAMEL TRÈS ÉPAISSE (la signature professionnelle) :\n1. Faire infuser oignon dans lait + crème à 80°C 15 min. Filtrer.\n2. Roux : beurre + farine 4 min en remuant.\n3. Verser lait infusé chaud en filet en fouettant. Cuire 12 min en remuant constamment — béchamel TRÈS épaisse.\n4. Hors feu, incorporer jamón Ibérico haché + sel + poivre + muscade.\n5. Étaler sur plaque chemisée 2 cm épaisseur. Filmer au contact. RÉFRIGÉRER 8 H MINIMUM (24 h idéal — la base devient ferme).\nFAÇONNAGE :\n6. Avec mains farinées, former croquettes ovales de 5 cm. La base réfrigérée ferme tient parfaitement.\nPANURE TRIPLE :\n7. Farine → œuf battu → panko. Presser pour bien adhérer.\nFRITURE PROFESSIONNELLE :\n8. Chauffer huile à 180°C. Frire 3 min par fournée jusqu'à dorées profondes.\n9. Égoutter sur grille. Saler immédiatement.\nSERVICE :\n10. Servir IMMÉDIATEMENT sur planche en bois — l'extérieur est croustillant, le cœur est crémeux et coulant (textures contrastées = signature Arola).",vin:"Sherry Manzanilla en Rama ou Albariño Rías Baixas",notes:"Sergi Arola (★★ Madrid) : la base béchamel TRÈS épaisse + repos 24 h sont les secrets professionnels. Le jamón Ibérico Bellota DOP est obligatoire — toute autre charcuterie est une trahison espagnole."},
{id:"ES010",co:"Espagne",cat:"Plat",sous:"Viande",nom:"Cocido Madrileño (Pot-au-Feu Madrilène)",chef:"Tradition madrilène",bp:8,prep:30,cui:180,diff:2,qual:4,ig:[["Pois chiches secs trempés",400,"g"],["Jarret de boeuf",500,"g"],["Poulet",1,"pièce"],["Chorizo",200,"g"],["Morcilla",1,"pièce"],["Jamón serrano os",100,"g"],["Carottes navets",1,"qs"],["Oignon ail",1,"qs"],["Vermicelles",100,"g"]],et:"1. Dans grande marmite : pois chiches + viandes + os + légumes + sel. Couvrir d'eau froide.\n2. Porter à frémissement, écumer méticuleusement. Cuire à feu doux 2h30.\n3. Cuire le chorizo et morcilla séparément 30 min.\nService en 3 temps :\n4. 1er : bouillon avec vermicelles cuits dedans.\n5. 2e : pois chiches + légumes. 3e : viandes + charcuteries.",vin:"Ribera del Duero rouge ou Rioja Reserva",notes:"Le cocido madrileño se sert toujours en 3 services distincts dans l'ordre traditionnel."},
{id:"ES011",co:"Espagne",cat:"Dessert",sous:"Entremets",nom:"Tarta de Santiago",chef:"Tradition galicienne",bp:8,prep:20,cui:35,diff:1,qual:4,ig:[["Poudre d'amandes",250,"g"],["Sucre",250,"g"],["Oeufs",4,"pièces"],["Zeste de citron non traité",1,"pièce"],["Zeste d'orange",1,"pièce"],["Cannelle",1,"cc"],["Amandes entières",30,"g"],["Sucre glace",30,"g"]],et:"1. Fouetter oeufs + sucre jusqu'à légèrement mousseux.\n2. Incorporer poudre d'amandes + zestes + cannelle. Mélanger jusqu'à homogène.\n3. Verser dans un moule beurré et fariné de 24cm.\n4. Déposer quelques amandes entières sur le dessus.\n5. Four 170°C 30-35 min. Refroidir complètement. Poser le patron de la Croix de Saint-Jacques. Saupoudrer de sucre glace. Retirer le patron.",vin:"Albariño de Rías Baixas ou Ribeiro blanc",notes:"La tarta de Santiago est naturellement sans gluten. La croix de Saint-Jacques est sa signature."},
{id:"ES012",co:"Espagne",cat:"Entrée",sous:"Gazpacho",nom:"Salmorejo Cordóbes",chef:"Tradition andalouse",bp:6,prep:15,cui:0,diff:1,qual:4,ig:[["Tomates très mûres",1000,"g"],["Pain de mie rassis",200,"g"],["Ail",2,"gousses"],["Huile d'olive extra-vierge",8,"cl"],["Vinaigre de Xérès",2,"cs"],["Sel",1,"qs"],["Oeufs durs",2,"pièces"],["Jamón serrano",50,"g"]],et:"1. Couper les tomates en quartiers. Mixer avec pain trempé dans un peu d'eau + ail.\n2. Avec le mixeur en marche, incorporer l'huile d'olive en filet jusqu'à émulsion crémeuse.\n3. Ajouter le vinaigre de Xérès. Assaisonner généreusement en sel.\n4. Réfrigérer 2h minimum.\n5. Servir dans des bols avec garniture : oeuf dur haché + jamón serrano en brunoise.",vin:"Fino de Jerez très frais",notes:"Le salmorejo est plus épais et plus riche que le gazpacho. Il doit napper une cuillère."},
{id:"ES013",co:"Espagne",cat:"Plat",sous:"Légumes",nom:"Escalivada Catalane",chef:"Tradition catalane",bp:4,prep:15,cui:45,diff:1,qual:4,ig:[["Poivrons rouges",4,"pièces"],["Aubergines",2,"pièces"],["Oignons",2,"pièces"],["Tomates",2,"pièces"],["Ail",4,"gousses"],["Huile d'olive extra-vierge",8,"cs"],["Vinaigre de Xérès",2,"cs"],["Sel poivre",1,"qs"],["Persil",0.5,"bouquet"]],et:"1. Poser tous les légumes entiers sur la braise ou directement sur la flamme du gaz. Les faire noircir sur toutes les faces.\n2. Placer dans un sac plastique fermé 15 min pour les faire suer.\n3. Éplucher tous les légumes. Éliminer les graines des poivrons.\n4. Couper en lanières régulières. Disposer dans un plat.\n5. Arroser généreusement d'huile d'olive + vinaigre + ail haché + sel + poivre + persil.",vin:"Garnacha Blanca du Priorat ou Cava Brut Nature",notes:"L'escalivada est meilleure tiède ou à température ambiante, jamais chaude."},
{id:"ES014",co:"Espagne",cat:"Plat",sous:"Riz",nom:"Fideuà Valenciana",chef:"Tradition de Gandia (Communauté valencienne)",bp:6,prep:20,cui:25,diff:3,qual:4,ig:[["Vermicelles fins (fideos)",500,"g"],["Bouillon de poisson chaud",150,"cl"],["Crevettes roses",300,"g"],["Calamars",300,"g"],["Tomates concassées",200,"g"],["Safran",0.3,"g"],["Paprika fumé doux",1,"cs"],["Ail",4,"gousses"],["Huile d'olive",6,"cs"],["Aioli",1,"qs"]],et:"1. Dans paella : saisir crevettes + calamars dans huile. Réserver.\n2. Suer ail + tomates dans le même gras. Ajouter paprika. Cuire le sofrito 8 min.\n3. Ajouter les vermicelles. Nacrer 2 min jusqu'à légèrement dorés.\n4. Verser bouillon + safran. NE PAS remuer. Cuire à feu vif 5 min, puis moyen 5 min.\n5. Remettre fruits de mer. Socarrat final. Servir avec aioli.",vin:"Cava Brut Nature ou Muscat sec de Valence",notes:"La fideuà est la version aux vermicelles de la paella. Le socarrat (croûte foncée) est obligatoire."},
{id:"ES015",co:"Espagne",cat:"Entrée",sous:"Tapas",nom:"Boquerones en Vinagre (Anchois Marinés)",chef:"Tradition andalouse",bp:6,prep:20,cui:0,diff:1,qual:4,ig:[["Filets d'anchois frais ou décongelés",400,"g"],["Vinaigre de vin blanc",20,"cl"],["Ail",4,"gousses"],["Persil plat",1,"bouquet"],["Huile d'olive extra-vierge",8,"cs"],["Sel",1,"qs"]],et:"1. Nettoyer les anchois, lever les filets, rincer soigneusement.\n2. Disposer dans un plat. Couvrir de vinaigre blanc + sel. Réfrigérer 4-6h (les filets doivent blanchir).\n3. Rincer les filets sous l'eau froide. Sécher soigneusement.\n4. Disposer dans plat de service. Arroser d'huile d'olive.\n5. Parsemer d'ail haché finement + persil ciselé.",vin:"Manzanilla en Rama ou Fino de Jerez très frais",notes:"Les anchois sont 'cuits' par l'acidité du vinaigre. Le blanchissement indique la bonne marinade."},
{id:"ES016",co:"Espagne",cat:"Plat",sous:"Légumes",nom:"Pisto Manchego",chef:"Tradition de La Mancha",bp:4,prep:20,cui:35,diff:1,qual:4,ig:[["Courgettes",3,"pièces"],["Poivrons rouges verts",2,"pièces"],["Aubergine",1,"pièce"],["Tomates mûres",4,"pièces"],["Oignons",2,"pièces"],["Ail",3,"gousses"],["Huile d'olive",8,"cs"],["Sel poivre",1,"qs"],["Oeufs au plat (optionnel)",4,"pièces"]],et:"1. Couper tous les légumes en dés réguliers de 1.5cm.\n2. Suer oignons + ail dans l'huile 10 min.\n3. Ajouter poivrons. Cuire 8 min. Ajouter aubergines. Cuire 5 min.\n4. Ajouter courgettes + tomates concassées. Assaisonner.\n5. Cuire à feu doux 20 min jusqu'à légumes fondants. Servir avec œuf au plat ou en accompagnement.",vin:"Garnacha ou Tempranillo de La Mancha",notes:"Le pisto est le cousin espagnol de la ratatouille française. Chaque légume cuit dans l'ordre de sa dureté."},
{id:"ES017",co:"Espagne",cat:"Dessert",sous:"Riz",nom:"Arroz con Leche (Riz au Lait Espagnol)",chef:"Tradition espagnole",bp:6,prep:10,cui:45,diff:1,qual:4,ig:[["Riz rond",150,"g"],["Lait entier",120,"cl"],["Sucre",120,"g"],["Cannelle bâton",1,"pièce"],["Zeste de citron",1,"pièce"],["Zeste d'orange",1,"pièce"],["Cannelle moulue pour servir",1,"qs"],["Beurre",20,"g"]],et:"1. Porter le lait à frémissement avec cannelle bâton + zestes d'agrumes.\n2. Ajouter le riz. Cuire à feu doux en remuant régulièrement 35-40 min.\n3. Le riz doit absorber presque tout le lait et devenir très crémeux.\n4. Ajouter sucre + beurre en fin de cuisson. Mélanger.\n5. Verser dans coupes. Refroidir. Saupoudrer de cannelle moulue avant de servir.",vin:"Moscatel de Valencia ou café solo",notes:"L'arroz con leche se sert à T° ambiante ou légèrement frais. Jamais froid du frigo."},
{id:"ES018",co:"Espagne",cat:"Plat",sous:"Agneau",nom:"Cordero Lechal Asado (Agneau de Lait Rôti Castillan)",chef:"Tradition castillane",bp:6,prep:15,cui:90,diff:1,qual:4,ig:[["Épaules de jeune agneau de lait",2,"pièces"],["Eau",15,"cl"],["Saindoux ou huile d'olive",2,"cs"],["Sel",2,"cc"],["Vinaigre de vin blanc",2,"cs"],["Ail",4,"gousses"]],et:"1. Préchauffer four 220°C.\n2. Frotter les épaules de sel + saindoux. Les placer dans plat en terre (cazuela).\n3. Ajouter l'eau dans le fond du plat. Ail en chemise autour.\n4. Rôtir 220°C 20 min pour colorer. Puis 170°C 60-70 min.\n5. Arroser régulièrement du jus. En fin de cuisson, déglacer le plat avec un filet de vinaigre.",vin:"Ribera del Duero Reserva ou Rioja Gran Reserva",notes:"La tradition ségoviane : l'agneau de lait doit être si tendre qu'on le coupe avec l'assiette."},
{id:"ES019",co:"Espagne",cat:"Entrée",sous:"Fromage",nom:"Queso Manchego con Membrillo",chef:"Tradition de La Mancha",bp:4,prep:10,cui:0,diff:1,qual:4,ig:[["Manchego affiné curado ou viejo",300,"g"],["Pâte de coing (membrillo)",150,"g"],["Noix de Grenoble",40,"g"],["Huile d'olive extra-vierge",2,"cs"],["Romarin",1,"branche"]],et:"1. Trancher le manchego en fines lamelles ou en triangles.\n2. Couper la pâte de coing en cubes ou tranches de même taille.\n3. Disposer sur une planche ou ardoise : manchego + membrillo alternés.\n4. Parsemer de noix concassées. Filet d'huile d'olive sur le fromage. Branche de romarin.\n5. Servir avec pain de campagne grillé ou crackers.",vin:"Oloroso Seco de Jerez ou Ribera del Duero rouge",notes:"L'association manchego + membrillo est l'une des harmonies les plus parfaites de la gastronomie espagnole."},
{id:"ES020",co:"Espagne",cat:"Dessert",sous:"Crème catalane",nom:"Crema Catalana aux Agrumes",chef:"Tradition catalane — La plus ancienne crème brûlée",bp:6,prep:15,cui:20,diff:2,qual:5,ig:[["Lait entier",75,"cl"],["Jaunes d'oeufs",6,"pièces"],["Sucre",120,"g"],["Maïzena",20,"g"],["Zeste de citron non traité",1,"pièce"],["Zeste d'orange",1,"pièce"],["Cannelle bâton",1,"pièce"],["Sucre pour brûler",60,"g"]],et:"1. Infuser lait + zestes + cannelle à frémissement 10 min. Filtrer.\n2. Fouetter jaunes + sucre + maïzena jusqu'à homogène.\n3. Verser lait chaud en filet sur les jaunes en fouettant.\n4. Remettre à feu doux en fouettant jusqu'à épaississement (ne pas bouillir).\n5. Verser dans 6 cazuelitas en terre. Refroidir 4h. Saupoudrer sucre fin. Brûler au fer rouge ou chalumeau.",vin:"Muscat sec d'Espagne ou Cava Brut Nature",notes:"Antérieure à la crème brûlée française, la crema catalana se distingue par l'arôme des zestes d'agrumes et de cannelle. Le fer rouge est la méthode traditionnelle."},
{id:"ES021",co:"Espagne",cat:"Dessert",sous:"Pâtisserie",nom:"Polvorones de Mantequilla",chef:"Tradition andalouse — Pâtisserie de Noël",bp:20,prep:20,cui:15,diff:1,qual:4,ig:[["Farine T55 torréfiée",300,"g"],["Beurre pommade",150,"g"],["Saindoux",50,"g"],["Sucre glace",100,"g"],["Amandes mondées torréfiées en poudre",100,"g"],["Cannelle",1,"cc"],["Sel",1,"pincée"]],et:"1. Torréfier la farine à four 160°C 20 min jusqu'à légèrement dorée et parfumée. Refroidir complètement.\n2. Mélanger farine + poudre d'amandes + sucre glace + cannelle.\n3. Incorporer beurre + saindoux en pétrissant jusqu'à pâte qui s'émiette (ne pas trop travailler).\n4. Former des boudins, couper en tronçons, façonner en ovales.\n5. Four 180°C 12-15 min. Refroidir ENTIÈREMENT avant de toucher. Rouler dans sucre glace.",vin:"Oloroso Seco ou Palo Cortado de Jerez",notes:"Les polvorones se désintègrent dans la bouche comme de la poudre (polvo = poussière). Ils doivent refroidir entièrement sinon ils s'effritent."},
{id:"ES022",co:"Espagne",cat:"Dessert",sous:"Entremets",nom:"Leche Frita (Lait Frit Madrilène)",chef:"Tradition madrilène",bp:6,prep:20,cui:20,diff:2,qual:4,ig:[["Lait entier",80,"cl"],["Maïzena",80,"g"],["Sucre",100,"g"],["Oeufs",2,"pièces"],["Zeste de citron",1,"pièce"],["Cannelle bâton",1,"pièce"],["Oeuf pour paner",1,"pièce"],["Farine pour paner",50,"g"],["Huile pour frire",50,"cl"],["Sucre cannelle pour servir",1,"qs"]],et:"1. Infuser lait + cannelle + zeste 10 min. Filtrer.\n2. Délayer maïzena dans 10cl de lait froid. Fouetter oeufs + sucre. Tout réunir.\n3. Cuire à feu moyen en fouettant sans cesse jusqu'à très épaisse. Verser dans plat 2cm. Réfrigérer 4h.\n4. Couper en carrés. Paner farine + oeuf battu.\n5. Frire à 175°C jusqu'à dorés croustillants. Servir immédiatement avec sucre + cannelle.",vin:"Manzanilla fraîche ou café cortado",notes:"La leche frita est la contradiction parfaite : crème froide et crémeuse à l'intérieur, croustillante à l'extérieur."},
{id:"ES023",co:"Espagne",cat:"Plat",sous:"Riz",nom:"Paella Mixta Valencienne",chef:"Tradition valencienne — Recette de la Communauté valencienne",bp:6,prep:20,cui:40,diff:4,qual:5,ig:[["Riz Senia ou Bomba",500,"g"],["Poulet coupé en morceaux",800,"g"],["Lapin coupé en morceaux",400,"g"],["Haricots plats verts (garrofó)",200,"g"],["Haricots blancs cuits",100,"g"],["Tomates râpées",3,"pièces"],["Paprika valencien",1,"cs"],["Safran",0.4,"g"],["Bouillon de poulet chaud",150,"cl"],["Huile d'olive",8,"cs"],["Romarin",2,"branches"]],et:"1. Paella (poêle à paella 40cm). Chauffer l'huile. Saisir poulet + lapin sur toutes les faces jusqu'à très dorés. Saler.\n2. Pousser les viandes sur les bords. Au centre : revenir les haricots verts. Ajouter tomates râpées. Cuire 5 min (sofrito).\n3. Ajouter paprika. Immédiatement verser le bouillon + safran. Porter à ébullition. Goûter, rectifier sel.\n4. Répartir le riz uniformément. NE PLUS JAMAIS REMUER.\n5. Feu vif 10 min. Feu moyen 8 min. Feu minimal 2 min pour le socarrat. Romarin dessus. Reposer 5 min.",vin:"Cava Brut ou Garnacha blanche valencienne",notes:"La paella ORIGINALE n'a pas de fruits de mer. Poulet + lapin uniquement. Ne jamais remuer le riz. Le socarrat (croûte du fond) est obligatoire."},
{id:"ES024",co:"Espagne",cat:"Plat",sous:"Tapas",nom:"Gambas al Ajillo",chef:"Tradition madrilène",bp:4,prep:10,cui:5,diff:1,qual:5,ig:[["Gambas entières fraîches",600,"g"],["Ail",8,"gousses"],["Piment guindilla ou cayenne",2,"pièces"],["Huile d'olive extra-vierge",10,"cs"],["Vin blanc Manzanilla",3,"cs"],["Sel fleur de sel",1,"qs"],["Persil haché",1,"cs"]],et:"1. Décortiquer les gambas en gardant la tête (le jus dans la tête est précieux).\n2. Dans cazuela en terre ou poêle : chauffer l'huile à feu vif avec ail tranché + piment jusqu'à ail blond doré.\n3. Ajouter les gambas en une couche. Cuire exactement 1 min sans toucher.\n4. Retourner. Ajouter vin blanc. Cuire encore 30 sec.\n5. Fleur de sel + persil. Servir IMMÉDIATEMENT dans la cazuela brûlante.",vin:"Manzanilla en Rama ou Fino de Jerez très froid",notes:"Les gambas al ajillo se cuisent et se servent dans la même cazuela brûlante. Temps total de cuisson : 90 secondes maximum."},
{id:"ES025",co:"Espagne",cat:"Plat",sous:"Légumineuses",nom:"Fabada Asturiana",chef:"Tradition des Asturies",bp:8,prep:20,cui:180,diff:2,qual:5,ig:[["Fabes (gros haricots blancs asturiens) trempés",500,"g"],["Chorizo asturien",200,"g"],["Morcilla asturiana (boudin noir)",200,"g"],["Lard salé dessalé",150,"g"],["Jambon ibérique os",150,"g"],["Oignon",1,"pièce"],["Ail",4,"gousses"],["Safran",0.3,"g"],["Paprika doux",1,"cc"],["Huile d'olive",4,"cs"]],et:"1. Tremper les fabes 12h. Cuire DÉPART EAU FROIDE avec toutes les charcuteries + oignon + ail. Ne jamais saler au début.\n2. Porter très lentement à frémissement en écumant.\n3. Cuire à feu très doux 2h-2h30. Les haricots doivent rester entiers mais fondre dans la bouche.\n4. Technique du 'asustado' : ajouter un verre d'eau froide si le bouillon bout trop.\n5. En fin de cuisson : retirer charcuteries, les trancher. Assaisonner. Ajouter safran dilué + paprika.",vin:"Albariño de Rías Baixas ou Sidra asturiana naturale",notes:"Les fabes asturiennes DOP sont irremplaçables. L'asustado (refroidissement brutal) évite que les haricots éclatent. Meilleur le lendemain."},
{id:"ES026",co:"Espagne",cat:"Entrée",sous:"Soupe",nom:"Ajo Blanco (Gazpacho Blanc Malaguène)",chef:"Tradition de Málaga",bp:4,prep:15,cui:0,diff:1,qual:5,ig:[["Amandes blanches mondées",150,"g"],["Pain de mie rassis trempé",100,"g"],["Ail",2,"gousses"],["Vinaigre de Xérès",3,"cs"],["Huile d'olive extra-vierge",8,"cs"],["Eau glacée",25,"cl"],["Sel",1,"qs"],["Raisins muscat",80,"g"]],et:"1. Tremper le pain dans l'eau 5 min. Essorer.\n2. Mixer amandes + pain essoré + ail jusqu'à pâte très fine.\n3. Ajouter vinaigre de Xérès + sel. Mixer.\n4. Avec le mixer en marche : incorporer l'huile en filet très fin jusqu'à émulsion.\n5. Ajouter eau glacée jusqu'à consistance crémeuse. Réfrigérer 4h. Servir glacé avec les grains de muscat.",vin:"Manzanilla fraîche ou Fino de Jerez",notes:"L'ajo blanco est antérieur au gazpacho rouge (avant l'introduction de la tomate en Europe). C'est l'un des plats les plus anciens d'Espagne."},
{id:"ES027",co:"Espagne",cat:"Plat",sous:"Riz",nom:"Paella Marinera Valenciana",chef:"Tradition côtière de Valence",bp:6,prep:30,cui:40,diff:3,qual:5,ig:[["Riz Bomba",500,"g"],["Fruits de mer mélangés",800,"g"],["Crevettes royales",250,"g"],["Moules",300,"g"],["Crevettes roses",150,"g"],["Safran du Puy",0.5,"g"],["Bouillon de poisson",150,"cl"],["Ail",4,"gousses"],["Paprika doux",1,"cs"],["Huile d'olive",8,"cs"]],et:"1. Paella chauffée. Huile + ail + safran + paprika.\n2. Verser riz sec, nacrer 2 min. NE PAS REMUER.\n3. Verser bouillon bouillant. Porter à ébullition.\n4. À mi-cuisson (10 min) : ajouter fruits de mer variés en cercles. Moulins par-dessus.\n5. Feu vif 5 min pour socarrat. Repos 5 min. Décorer citron + persil.",vin:"Cava brut ou Albariño galicien",notes:"Paella marinera authentique : fruits de mer variés, jamais porc. Respecter les 4 phases de cuisson."},
{id:"ES028",co:"Espagne",cat:"Plat",sous:"Riz",nom:"Arroz Rojo Español",chef:"Tradition espagnole",bp:6,prep:20,cui:40,diff:2,qual:4,ig:[["Riz court",400,"g"],["Bouillon de poule",100,"cl"],["Tomates concassées",300,"g"],["Oignons",2,"pièces"],["Ail",3,"gousses"],["Safran",0.3,"g"],["Paprika fumé",1,"cc"],["Petits pois",100,"g"],["Huile d'olive",6,"cs"]],et:"1. Suer oignons + ail. Ajouter riz sec, nacrer 2 min.\n2. Ajouter tomates + safran + paprika. Ajouter bouillon à ébullition.\n3. Feu vif 5 min. Feu moyen 25 min. NE PAS REMUER.\n4. Ajouter petits pois 5 min avant fin. Repos 5 min.\n5. Reposer sous linge humide.",vin:"Tempranillo jeune ou Côte du Rhône"},
{id:"ES029",co:"Espagne",cat:"Sauce / Base",sous:"Española",nom:"Sofrito Español Classique",chef:"Cuisine campagnarde espagnole",bp:4,prep:15,cui:30,diff:1,qual:5,ig:[["Oignons",2,"pièces"],["Poivrons rouges",2,"pièces"],["Tomates bien mûres",3,"pièces"],["Ail",3,"gousses"],["Huile d'olive",8,"cs"],["Sel",1,"cc"],["Paprika doux optionnel",0.5,"cc"]],et:"1. Émincer oignons très finement. Épépiner et couper poivrons en dés.\n2. Suer oignons dans l'huile à feu doux 10 min sans colorer.\n3. Ajouter poivrons. Cuire 10 min en remuant régulièrement.\n4. Monder tomates. Couper en petits dés. Ajouter ail.\n5. Cuire à feu moyen 10 min jusqu'à réduit. Peut être congelé.",vin:"Usage : base pour gazpachos, paella, ragôuts"},
{id:"ES030",co:"Espagne",cat:"Plat",sous:"Abats",nom:"Criadillas al Champagne Madrileño",chef:"Tradition madrilène courtisane",bp:4,prep:20,cui:15,diff:3,qual:5,ig:[["Criadillas",600,"g"],["Champagne",25,"cl"],["Crème fraîche",20,"cl"],["Beurre",40,"g"],["Échalotes",2,"pièces"],["Persil",1,"cs"],["Sel poivre",1,"qs"]],et:"1. Nettoyer criadillas (testicules d'animal — viande blanche délicate).\n2. Faire fondre beurre. Ajouter échalotes finement ciselées.\n3. Saisir criadillas 3 min/ côté jusqu'à légèrement dorées. Réserver.\n4. Déglacer Champagne. Réduire de moitié. Ajouter crème fraîche.\n5. Remettre criadillas. Parsemer persil. Servir immédiatement.",vin:"Champagne brut ou Cava meilleur cuvée"},
{id:"ES032",co:"Espagne",cat:"Plat",sous:"Volaille",nom:"Pollo al Ajillo Catalan",chef:"Tradition catalane montagnarde",bp:4,prep:15,cui:25,diff:2,qual:4,ig:[["Poulet fermier coupé",1200,"g"],["Ail",8,"gousses"],["Paprika fumé",1,"cs"],["Piment sec",1,"piment"],["Vin blanc Pénédès",15,"cl"],["Huile d'olive",6,"cs"],["Sel poivre",1,"qs"],["Persil",2,"cs"]],et:"1. Dorer poulet sur toutes les faces dans l'huile + ail écrasé. Assaisonner.\n2. Poudrer légèrement paprika.\n3. Déglacer vin blanc. Réduire 3 min.\n4. Couvrir. Mijoter 20 min à feu moyen.\n5. Découvrir. Réduire sauce. Parsemer persil.",vin:"Penedès blanc ou Côte du Rhône rouge"},
{id:"ES033",co:"Espagne",cat:"Plat",sous:"Épinards",nom:"Escalivada Catalaña",chef:"Tradition catalane des gril",bp:6,prep:15,cui:30,diff:1,qual:4,ig:[["Aubergines",2,"pièces"],["Poivrons rouges jaunes",3,"pièces"],["Tomates",2,"pièces"],["Oignons",2,"pièces"],["Ail",4,"gousses"],["Huile d'olive",8,"cs"],["Sel fleur de sel",1,"qs"]],et:"1. Couper tous les légumes en gros morceaux. Saler légèrement.\n2. Disposer sur grille. Gril ou four très chaud 30 min.\n3. Légumes doivent être calcinés sur les bords, fondants dedans.\n4. Refroidir légèrement. Dresser sur assiette.\n5. Filet d'huile d'olive crue. Ail cru haché fin.",vin:"Escalivada = accompagnement universel"},
{id:"ES034",co:"Espagne",cat:"Entrée",sous:"Jamón",nom:"Jamón Ibérico Bellota en Jamón",chef:"Tradition d'Huelva",bp:4,prep:5,cui:0,diff:1,qual:5,ig:[["Jamón Ibérico 100% bellota",200,"g"]],et:"1. Jamón ibérico bellota doit être au T° ambiante 30 min avant service.\n2. Découper très fin à la main avec couteau long et mince — jamais épais.\n3. Disposer sur planche ou assiette.\n4. Aucun accompagnement — juste le jamón et le pain si désiré.\n5. Avant service : jamais au frigo moins d'1h.",vin:"Fino de Jerez ou Manzanilla en Rama très froid",notes:"Jamón ibérico 100% bellota : porc nourri au gland seul. Texture fond en bouche, saveur noisette. Achat chez fiable espagnol."},
{id:"ES035",co:"Espagne",cat:"Plat",sous:"Légumineuses",nom:"Lentejas de Bellvís",chef:"Tradition andalouse",bp:6,prep:20,cui:45,diff:1,qual:4,ig:[["Lentilles grise Bellvís",300,"g"],["Oignons",2,"pièces"],["Carottes",1,"pièce"],["Ail",3,"gousses"],["Jambon ibérique",100,"g"],["Paprika fumé",1,"cc"],["Huile d'olive",4,"cs"],["Sel poivre",1,"qs"],["Bouillon",80,"cl"]],et:"1. Suer soffritto (oignon + carotte + ail) dans l'huile.\n2. Ajouter lentilles + jambon coupé + paprika + bouillon.\n3. Portrer à ébullition. Réduire feu. Couvrir.\n4. Mijoter 40 min. Lentilles doivent rester entières.\n5. Assaisonner en fin de cuisson uniquement.",vin:"Manzanilla sec ou Albarino"},
{id:"ES036",co:"Espagne",cat:"Plat",sous:"Poisson",nom:"Pulpo à la Gallega",chef:"Tradition galicienne côtière",bp:4,prep:15,cui:30,diff:2,qual:5,ig:[["Pieuvre fraîche",800,"g"],["Pommes de terre",300,"g"],["Paprika fumé",1,"cc"],["Sel fleur de sel",1,"qs"],["Huile d'olive",6,"cs"],["Gros sel pour cuisson",1,"qs"]],et:"1. Cuire pieuvre 25-30 min dans eau salée frémissante (+ feuille laurier si désiré).\n2. Cuire pommes de terre entières pelées dans eau salée 15 min.\n3. Couper pieuvre en tronçons 2cm. Trancher pommes de terre en rondelles.\n4. Dresser sur assiette en bois. Arroser d'huile d'olive.\n5. Saupoudrer paprika + fleur de sel généreusement.",vin:"Rioxa Blanco galicienne ou Albarino frais"},
{id:"ES037",co:"Espagne",cat:"Plat",sous:"Charcuterie",nom:"Chorizo Estremadura Empanadillas",chef:"Tradition d'Estrémadure",bp:6,prep:30,cui:20,diff:2,qual:4,ig:[["Pâte brisée",350,"g"],["Chorizo frais haché",150,"g"],["Paprika fumé",1,"cc"],["Oignons",1,"pièce"],["Poivre noir",1,"cc"],["Oeuf pour dorure",1,"pièce"]],et:"1. Suer oignons uniquement — ne pas ajouter graisse.\n2. Ajouter chorizo haché. Cuire 5 min. Refroidir.\n3. Abaisser pâte. Découper ronds Ø7cm.\n4. Remplir de farce. Refermer en demi-lune. Souder bords.\n5. Dorer à l'oeuf. Four 200°C 18-20 min.",vin:"Vino de Estrémadure rouge"},
{id:"ES038",co:"Espagne",cat:"Entrée",sous:"Gazpacho",nom:"Salmorejo Cordobés",chef:"Tradition de Cordoue",bp:4,prep:15,cui:0,diff:1,qual:5,ig:[["Tomates bien mûres",1000,"g"],["Pain de mie rassis",150,"g"],["Ail",2,"gousses"],["Vinaigre de Xérès",3,"cs"],["Huile d'olive",10,"cs"],["Sel",1,"qs"],["Jamón ibérique",60,"g"],["Oeuf dur",1,"pièce"]],et:"1. Tremper pain dans un peu d'eau 5 min. Essorer.\n2. Mixer tomates pelées (ébouillanté) + pain essoré + ail jusqu'à lisse absolue.\n3 Ajouter vinaigre + sel. Mixer.\n4. En mixer marche : incorporer huile en filet lent jusqu'à émulsion très épaisse.\n5. Servir dans bol. Garnir dés de jamón + oeuf dur émietté.",vin:"Fino ou Manzanilla fraîche glacée"},
{id:"ES039",co:"Espagne",cat:"Plat",sous:"Riz",nom:"Arroz Negro con Tinta de Sepia",chef:"Tradition côtière de Murcie",bp:4,prep:20,cui:25,diff:2,qual:5,ig:[["Riz court",320,"g"],["Sepia / Calmar",500,"g"],["Encre de Sepia",3,"cs"],["Bouillon de poisson",80,"cl"],["Ail",3,"gousses"],["Oignons",1,"pièce"],["Vin blanc",10,"cl"],["Huile d'olive",6,"cs"]],et:"1. Nettoyer sepia. Couper en anneaux épais. Réserver encre.\n2. Suer soffritto (oignon + ail). Ajouter sepia. Cuire 10 min.\n3. Ajouter riz sec. Nacrer 2 min. Déglacer vin blanc.\n4. Verser bouillon + encre (crémeuse intensément noire). Feu vif 20 min. NE PAS REMUER.\n5. Repos 5 min. Feu pour socarrat si désiré.",vin:"Jumilla blanca ou Priorate rosé"},
{id:"ES040",co:"Espagne",cat:"Plat",sous:"Pigeon",nom:"Pichón Relleno de Castilla",chef:"Tradition castillane de chasse",bp:4,prep:30,cui:40,diff:3,qual:5,ig:[["Pigeonneaux entiers",4,"pièces"],["Foie gras cuit",80,"g"],["Fruits séchés (abricots raisins)",80,"g"],["Ail",2,"gousses"],["Thym",2,"branches"],["Veau hachée fine",100,"g"],["Madère",5,"cl"],["Beurre",60,"g"],["Sel poivre",1,"qs"]],et:"1. Farce : suer ail. Ajouter veau + foie gras + fruits séchés hachés + Madère. Refroidir.\n2. Farcir pigeonnau. Brider.\n3. Dorer dans beurre 5 min. Four 200°C 30 min (rosé).\n4. Déglacé plat. Verser jus chaud.\n5. Reposer 5 min. Servir avec jus.",vin:"Ribera del Duero ou Tôro rojo"},
{id:"ES041",co:"Espagne",cat:"Dessert",sous:"Confiture",nom:"Dulce de Membrillo Clasico",chef:"Tradition valencienne des confiseries",bp:6,prep:30,cui:90,diff:2,qual:5,ig:[["Coings bien mûrs",1200,"g"],["Sucre",600,"g"],["Jus de citron",2,"cs"],["Eau",10,"cl"]],et:"1. Éplucher coings. Couper en quartiers. Remplissage eau partielle + limão.\n2. Cuire 45 min à feu moyen jusqu'à coings très tendres.\n3. Passer au moulin à légumes fin (éliminer pépins).\n4. Peser la pulpe. Ajouter sucre égal (ratio 1:1). Verser dans casserole épais.\n5. Cuire à feu doux 30-45 min en remuant sans cesse — doit atteindre 105°C (nappe).",vin:"Sucre invérsi — conserve excellent en bocal"},
{id:"ES042",co:"Espagne",cat:"Plat",sous:"Légumes",nom:"Cardo a la Madrileña",chef:"Tradition madrilène hiver",bp:4,prep:20,cui:40,diff:1,qual:5,ig:[["Cardes fraîches",1000,"g"],["Sauce blanche légère",50,"cl"],["Jambon ibérique",80,"g"],["Amandes moulues",3,"cs"],["Ail",2,"gousses"],["Sel poivre",1,"qs"]],et:"1. Nettoyer cardes. Couper en tronçons 5cm.\n2. Blanchir 10 min eau bouillante salée. Égoutter.\n3. Béchamel légère : beurre + farine + lait — pas épaisse.\n4. Mélanger cardes + sauce. Verser en plat. Jambon émietté + amandes.\n5. Four 180°C 25 min brièvement gratinée.",vin:"Blanco de Madrid ou Albariño"},
{id:"ES043",co:"Espagne",cat:"Entrée",sous:"Croquettes",nom:"Croquetas de Jamón Jamón",chef:"Tradition basque des bars",bp:6,prep:20,cui:10,diff:2,qual:4,ig:[["Jamón ibérique haché fin",200,"g"],["Beurre",50,"g"],["Farine T55",50,"g"],["Lait",50,"cl"],["Oeufs",3,"pièces"],["Panure fine",100,"g"],["Huile pour frire",50,"cl"],["Sel poivre muscade",1,"qs"]],et:"1. Béchamel épaisse : beurre + farine + lait à 85°C.\n2. Hors feu : ajouter jamón haché + sel + poivre + muscade.\n3. Verser dans plat. Refroidir complètement 4h (peut congeler).\n4. Façonner croquettes.Paner: farine → oeuf → panure.\n5. Frire 175°C 2 min / côté. Égoutter. Servir brûlant.",vin:"Vino blanco du Pays Basque ou bière locale"},
{id:"ES044",co:"Espagne",cat:"Plat",sous:"Ragoût",nom:"Conejo Guisado a la Andaluza",chef:"Tradition andalouse de chasse",bp:4,prep:20,cui:60,diff:2,qual:4,ig:[["Lapin fermier en morceaux",1200,"g"],["Tomates concassées",400,"g"],["Oignons",2,"pièces"],["Ail",4,"gousses"],["Vin blanc",20,"cl"],["Olives noires",60,"g"],["Paprika doux",1,"cc"],["Huile d'olive",6,"cs"],["Sel poivre",1,"qs"]],et:"1. Dorer lapin sur toutes les faces. Assaisonner. Réserver.\n2. Suer oignons + ail. Ajouter tomates + paprika. Cuire 5 min.\n3. Remettre lapin + vin blanc + olives.\n4. Couvrir. Mijoter 50 min à feu doux.\n5. Assaisonner. Servir avec pain toasté.",vin:"Manzanilla en Rama ou Córdoba rouge"},
{id:"ES045",co:"Espagne",cat:"Accompagnement",sous:"Légumes",nom:"Espinacas con Pasas y Piñones",chef:"Tradition grenadienne",bp:4,prep:10,cui:15,diff:1,qual:4,ig:[["Épinards frais",600,"g"],["Raisins secs",60,"g"],["Pignons",40,"g"],["Ail",2,"gousses"],["Huile d'olive",4,"cs"],["Sel poivre",1,"qs"]],et:"1. Laver épinards. Égoutter.\n2. Chauffer huile. Suer ail. Ajouter raisins 1 min.\n3. Ajouter épinards. Cuire 5 min en remuant.\n4. Pignons toastés. Ajouter. Mélanger bien.\n5. Assaisonner sel + poivre.",vin:"Accompagnement universel espagnol"},
{id:"ES046",co:"Espagne",cat:"Plat",sous:"Charcuterie",nom:"Morcilla Negra de Burgos",chef:"Tradition de Burgos",bp:4,prep:30,cui:20,diff:2,qual:5,ig:[["Morcilla negra de Burgos",600,"g"],["Pommes de terre cuites",200,"g"],["Oignons",2,"pièces"],["Beurre",30,"g"],["Paprika",0.5,"cc"],["Sel poivre",1,"qs"]],et:"1. Morcilla se coupe en tranches épaisses (1,5cm).\n2. Trancher pommes de terre.\n3. Faire fondre beurre. Ajouter oignons. Cuire 5 min.\n4. Ajouter morcilla + pommes de terre. Revenir 15 min.\n5. Paprika. Assaisonner. Servir très chaud.",vin:"Vino de Burgos ou Bière locale"},
{id:"ES047",co:"Espagne",cat:"Dessert",sous:"Flan",nom:"Flor de Sal Catalan",chef:"Tradition catalane",bp:6,prep:20,cui:40,diff:2,qual:5,ig:[["Blancs d'oeufs",6,"pièces"],["Sucre",200,"g"],["Eau",10,"cl"],["Caramel pour moule",1,"qs"],["Sel fleur",1,"pincée"]],et:"1. Caramel : 150g sucre + eau. Couler dans moule à flan. Refroidir.\n2. Blancs montés en neige très ferme.\n3. Sucre 50g fouetté dedans progressivement. Reste neutre pour tenir neige.\n4. Verser dans moule. Bain-marie au four 150°C 35-40 min. Centre légèrement tremblote.\n5. Refroidir. Démouler. Sel fleur dessus.",vin:"Moscato d'Asti ou Cava sucré"},
{id:"ES048",co:"Espagne",cat:"Plat",sous:"Volaille",nom:"Espetada Sevillana Poulet",chef:"Tradition sévillane de rue",bp:4,prep:15,cui:25,diff:1,qual:5,ig:[["Poitrine de poulet fermier",600,"g"],["Gros sel",2,"poignée"],["Piment sec",1,"piment"],["Ail",3,"gousses"],["Huile d'olive",4,"cs"],["Citron",1,"pièce"]],et:"1. Couper poitrine en morceaux épais — les enfiler sur broche.\n2. Braiser dans filet d'huile + ail écrasé + piment.\n3. Griller à la braise ou grill très chaud 20-25 min en tournant régulièrement.\n4. Doit être croustillant dehors, juteux dedans.\n5. Servir directement avec gros sel (+1 citron).",vin:"Fino de Jerez ou Manzanilla"},
{id:"ES049",co:"Espagne",cat:"Entrée",sous:"Oeufs",nom:"Huevo Poche en Tostada de Jamon",chef:"Tradition des meriendas castillane",bp:4,prep:15,cui:5,diff:1,qual:4,ig:[["Oeufs",4,"pièces"],["Pain rassis de campagne",4,"tranches"],["Jamón ibérique",60,"g"],["Huile d'olive",3,"cs"],["Sel poivre",1,"qs"]],et:"1. Toaster tranches de pain à la plancha avec huile d'olive — doivent être dorées croustillantes.\n2. Poêler jamón très rapidement jusqu'à croustillant. Réserver.\n3. Poacher 4 oeufs 3 min eau vinaigrée frémissante.\n4. Dresser sur tostadas : jamón + oeuf poché.\n5. Sel frais poivre + filet d'huile chaude.",vin:"Fino ou Manzanilla frais"},
{id:"ES050",co:"Espagne",cat:"Plat",sous:"Soupe",nom:"Marmitako Euskaldunak",chef:"Tradition basques pêcheurs",bp:4,prep:20,cui:30,diff:2,qual:5,ig:[["Thon rouge frais",600,"g"],["Pommes de terre",400,"g"],["Oignons",2,"pièces"],["Poivrons rouges",1,"pièce"],["Tomates",2,"pièces"],["Bouillon de poisson",80,"cl"],["Huile d'olive",6,"cs"],["Sel poivre",1,"qs"]],et:"1. Couper tous les légumes en cubes réguliers.\n2. Suer oignons dans l'huile. Ajouter poivron + tomate. Cuire 5 min.\n3. Ajouter pommes de terre + thon en cubes épais + bouillon.\n4. Couvrir. Mijoter 20 min. Thon doit rester rose.gauche\n5. Soupe doit être épaisse, riche.",vin:"Txakoli du Pays Basque blanc ou Sidra"},
{id:"ES051",co:"Espagne",cat:"Plat",sous:"Assaisonnement",nom:"Alcaparras Rellenas de Anchoa",chef:"Tradition andalouse",bp:4,prep:10,cui:0,diff:1,qual:5,ig:[["Alcaparres non salées",200,"g"],["Filets d'anchois",8,"pièces"],["Huile d'olive",3,"cs"]],et:"1. Rincer alcaparres. Égoutter.\n2. Farci chaque alcaparra avec 1/2 filet d'anchois.\n3. Mettre dans petit bocal. Couvrir d'huile.\n4. Refrigérater 24h minimum.\n5. Utiliser comme condiment tapas.",vin:"Accompagnement tapas universelle"},
{id:"ES052",co:"Espagne",cat:"Entremet",sous:"Crema",nom:"Crema Catalana Simplificado",chef:"Tradition de Barcelone",bp:4,prep:15,cui:35,diff:2,qual:5,ig:[["Lait",50,"cl"],["Crème 35%",20,"cl"],["Bâton cannelle",1,"pièce"],["Zeste d'orange",1,"pièce"],["Jaunes d'oeufs",5,"pièces"],["Maïzena",40,"g"],["Sucre",120,"g"],["Sucre cristal toppingl",2,"cs"]],et:"1. Infuser lait + crème + cannelle + zeste 30 min. Filtrer.\n2. Fouetter jaunes + 80g sucre + maïzena. Verser lait chaud en filet.\n3. Recuire à feu doux 3 min jusqu'à épaississement — nappe.\n4. Verser dans ramequins. Filmer au contact. Réfrigérer 4h.\n5. Caraméliser sucre cristal dessus au chalumeau.",vin:"Cava brut ou Moscato d'Asti"},
{id:"ES053",co:"Espagne",cat:"Plat",sous:"Poisson",nom:"Espadon Grillé à la Basque",chef:"Tradition franco-basque côtière",bp:4,prep:10,cui:15,diff:1,qual:5,ig:[["Espadon (pesca spada)",600,"g"],["Ail",3,"gousses"],["Persil plat",2,"cs"],["Huile d'olive",6,"cs"],["Citron frais",1,"pièce"],["Sel fleur de sel",1,"qs"],["Poivre noir",1,"cc"]],et:"1. Espadon en steaks épais 3cm. Assaisonner.\n2. Grill très chaud. Marquer 4 min/côté (rosé dedans).\n3. Sauce : ail + persil + huile + citron.\n4. Servir espadon. Napper sauce à l'ailloli.\n5. Fleur de sel + poivre noir.",vin:"Albariño galicienne ou Txakoli pays basque"},
{id:"ES054",co:"Espagne",cat:"Accompagnement",sous:"Légumineuses",nom:"Judías Verdes con Jamón",chef:"Tradition castillan",bp:4,prep:10,cui:15,diff:1,qual:4,ig:[["Haricots verts frais ou surgelés",600,"g"],["Jamón ibérique",100,"g"],["Ail",2,"gousses"],["Huile d'olive",3,"cs"],["Sel poivre",1,"qs"]],et:"1. Blanchir haricots 8 min eau salée. Égoutter.\n2. Suer ail dans l'huile. Ajouter jamón émietté. Cuire 1 min.\n3. Ajouter haricots. Sauté 5 min à feu vif.\n4. Assaisonner sel poivre.\n5. Très simple, très savoureux.",vin:"Accompagnement des grillades"},
{id:"ES055",co:"Espagne",cat:"Plat",sous:"Légumes",nom:"Ternasco de Aragon Rôti",chef:"Tradition aragon montagne",bp:4,prep:20,cui:60,diff:2,qual:5,ig:[["Agneau jeune (rack)",1200,"g"],["Ail",4,"gousses"],["Thym",3,"branches"],["Romarin",2,"branches"],["Laurier",1,"feuille"],["Huile d'olive",8,"cs"],["Sel poivre",1,"qs"]],et:"1. Piquer agneau de gousses d'ail.\n2. Frotter généreusement huile + herbes.\n3. Four 200°C 50-60 min selon taille (T° interne 62°C pour rosé).\n4. Repos 10 min sous papier alu.\n5. Trancher sous belles côtes. Jus de rôtissage.",vin:"Monte Bueno Tempranillo ou Côté Gascogne rouge"},
{id:"SA007",co:"Espagne",cat:"Sauce / Base",sous:"Sauce espagnole",nom:"Sofrito Catalan",chef:"Tradition catalane",bp:6,prep:10,cui:40,diff:1,qual:4,ig:[["Tomates mûres",600,"g"],["Oignons",2,"pièces"],["Ail",4,"gousses"],["Poivron rouge",1,"pièce"],["Huile d'olive",6,"cs"],["Sel sucre",1,"qs"]],et:"1. Couper les tomates grossièrement. Hacher oignons + ail. Émincer le poivron.\n2. Chauffer l'huile à feu moyen. Suer oignons + ail 15 min jusqu'à très fondus.\n3. Ajouter poivron rouge. Cuire 5 min.\n4. Ajouter les tomates + sel + pincée de sucre. Cuire à feu doux 20-25 min.\n5. La sauce est prête quand elle est dense, brillante et que l'huile remonte légèrement à la surface.",vin:"Base : paella, fideuà, poulet basquaise, cocido",notes:"Le sofrito est la base aromatique de toute la cuisine espagnole et méditerranéenne. Il se congèle en portions."}
);
